('ayuda-2f04bde2-6cb7-461f-a67a-cc6e38428d26', 'Emergency Cash Transfer (ECT)', 'Nagbibigay ng temporary cash assistance sa mga pamilyang naapektuhan ng kalamidad para makatulong sa kanilang immediate basic needs habang nagre-recover.', 'Padre Paredes St, Sampaloc, Manila, 1015 Metro Manila, Philippines', 'Manila', 'ChIJWbJOsfjJlzMRjgaarMoSTa0', 14.6041190, 120.9886247, 'https://maps.google.com/?cid=12487658003456722574', '2026-04-28 06:00:00', '2026-05-28 10:00:00', 'Severity of Impact', 'draft', 'upcoming', '', '2026-04-26 05:52:43', '2026-04-26 05:54:53'),
('ayuda-393bda0d-34ef-4e0a-a48f-a0754cde0579', 'Medical Assistance Services', 'Nagbibigay ng financial support para sa hospitalization, gamot, laboratory tests, at iba pang medical procedures ng indigent patients.', '667 United Nations Ave, Ermita, Manila, 1000 Metro Manila, Philippines', 'Manila', 'ChIJmeOPiSbKlzMR8KozaRg50wE', 14.5821698, 120.9826580, 'https://maps.google.com/?cid=131511591130868464', '2026-04-20 06:00:00', '2026-04-24 22:00:00', 'Indigent Patients', 'published', 'archived', '', '2026-04-26 06:00:56', '2026-04-26 06:02:32'),
('ayuda-3c16fc82-5348-4057-afba-f1ca08297ba9', 'Senate Medical Assistance', 'Nagbibigay ng medical financial assistance sa mga pasyenteng nangangailangan ng tulong sa hospital expenses sa pamamagitan ng endorsement mula sa opisina ng senador.', 'Gsis, financial center, Diosdado Macapagal Blvd, Pasay City, Metro Manila, Philippines', 'Pasay', 'ChIJizQ6keDLlzMRyc0Pwcc0Ze8', 14.5477631, 120.9843283, 'https://maps.google.com/?cid=17250251980254727625', '2026-12-31 23:59:00', '2026-12-31 23:59:00', 'Financially Hardship', 'draft', 'upcoming', '', '2026-04-26 06:05:32', '2026-04-26 06:08:24'),
('ayuda-575c51c2-d1e3-4138-84ce-fe7a5a8cfdef', 'Educational Assistance Program', 'Nagbibigay ng financial aid para matulungan ang mga estudyante na maipagpatuloy ang kanilang pag-aaral kahit may financial difficulties.', 'General Luna, corner Muralla St, Intramuros, Manila, 1002 Metro Manila, Philippines', 'Manila', 'ChIJUwB3NiPKlzMRBjWNdxQXcxs', 14.5867900, 120.9761774, 'https://maps.google.com/?cid=1977950038018307334', '2026-04-26 06:00:00', '2026-07-31 23:59:00', 'Working Students', 'published', 'active', '', '2026-04-26 06:02:45', '2026-04-26 06:05:14'),
('ayuda-7babb86d-4d57-4a8a-9ae5-6fecce6e2b2b', 'Humanitarian Assistance and Disaster Response (HADR)', 'Nagbibigay ng coordinated emergency support tulad ng food, temporary shelter, at essential services sa panahon ng sakuna.', 'RG2P+GFQ, Orani, Bataan, Philippines', 'Bataan', 'ChIJB_1XcYdCljMRuUb7p1LrNMI', 14.8013375, 120.5362344, 'https://maps.google.com/?cid=13994068682385082041', '2026-04-29 06:00:00', '2026-05-29 22:00:00', 'Displacement Status', 'published', 'upcoming', '', '2026-04-26 05:55:19', '2026-04-26 05:58:35'),
('ayuda-bf58e676-c56d-412c-9038-9e0625fa584f', 'Assistance to Individuals in Crisis Situations (AICS)', 'Nagbibigay ng financial o material assistance sa mga indibidwal o pamilya na dumaraan sa biglaang krisis tulad ng medical emergency, pagkamatay ng kapamilya, o matinding problemang pinansyal.', '646 Lee, Mandaluyong City, 1556 Kalakhang Maynila, Philippines', 'Mandaluyong', 'ChIJafTZojrIlzMRmNmEfqvGTMA', 14.5896813, 121.0456697, 'https://maps.google.com/?cid=13856668593376516504', '2026-04-27 06:00:00', '2026-05-27 22:00:00', 'Indigent Individuals/Families', 'published', 'upcoming', '', '2026-04-26 05:46:22', '2026-04-26 05:49:32'),
('ayuda-c18e9557-5996-4695-b81f-4fb16aaac7a5', 'Emergency Relief Supplies Distribution', 'Namimigay ng food packs at essential goods sa mga pamilyang direktang naapektuhan ng kalamidad.', 'Recto Ave, Binondo, Manila, Metro Manila, Philippines', 'Manila', 'EjVSZWN0byBBdmUsIEJpbm9uZG8sIE1hbmlsYSwgTWV0cm8gTWFuaWxhLCBQaGlsaXBwaW5lcyIuKiwKFAoSCdXAZlQEypczEYIV9Bzd80coEhQKEgkJiTQtEMqXMxH43041KSCr7Q', 14.6060579, 120.9746335, 'https://maps.google.com/?q=Recto+Ave,+Binondo,+Manila,+Metro+Manila,+Philippines&ftid=0x3397ca045466c0d5:0x2847f3dd1cf41582', '2026-04-30 06:00:00', '2026-05-30 22:00:00', 'Household Status', 'published', 'upcoming', '', '2026-04-26 05:58:48', '2026-04-26 06:00:38'),
('ayuda-d933188a-6366-462a-8967-5f8889594207', 'Unemployment Insurance / Involuntary Separation Benefits', 'Nagbibigay ng temporary income support sa mga empleyadong nawalan ng trabaho dahil sa authorized causes tulad ng retrenchment o company closure.', 'G3H9+HX6, Gen. Luna St, Taguig, 1637 Metro Manila, Philippines', 'Taguig', 'ChIJN-W97aTIlzMRIVzpIHRLwnQ', 14.5289240, 121.0698904, 'https://maps.google.com/?cid=8413370016021961761', '2026-05-05 06:00:00', '2026-08-26 22:00:00', 'Employment Sector', 'published', 'upcoming', '', '2026-04-26 06:08:45', '2026-04-26 06:10:38')
